UPDATE words SET example_en_2 = 'Epistemology asks how we can justify our beliefs.', example_ko_2 = '인식론은 우리의 믿음을 어떻게 정당화할 수 있는지를 묻는 학문이에요.', example_en_3 = 'Her thesis challenged traditional epistemology in science.', example_ko_3 = '그녀의 논문은 과학의 전통적 인식론에 의문을 제기했어요.', example_en_4 = 'Epistemology lies at the heart of research methodology.', example_ko_4 = '인식론은 연구 방법론의 핵심에 있어요.', example_en_5 = 'We must ground our inquiry in a coherent epistemology.', example_ko_5 = '우리는 일관된 인식론을 바탕으로 탐구를 진행해야 해요.' WHERE id = 'w_education_C1_01';
UPDATE words SET example_en_2 = 'Pedagogy must adapt to diverse learner needs.', example_ko_2 = '교육학은 다양한 학습자의 필요에 맞게 적응해야 해요.', example_en_3 = 'Her pedagogy emphasises collaborative inquiry over rote learning.', example_ko_3 = '그녀의 교육학은 암기보다 협력적 탐구를 강조해요.', example_en_4 = 'Critical pedagogy challenges oppressive educational structures.', example_ko_4 = '비판 교육학은 억압적인 교육 구조에 도전해요.', example_en_5 = 'The seminar explored new directions in pedagogy for higher education.', example_ko_5 = '세미나에서는 고등 교육을 위한 새로운 교육학 방향을 탐구했어요.' WHERE id = 'w_education_C1_02';
UPDATE words SET example_en_2 = 'A paradigm shift can transform an entire field of study.', example_ko_2 = '패러다임의 전환은 연구 분야 전체를 변화시킬 수 있어요.', example_en_3 = 'The dominant paradigm in linguistics has been challenged recently.', example_ko_3 = '언어학의 지배적 패러다임이 최근 도전을 받고 있어요.', example_en_4 = 'Kuhn argued that science progresses through paradigm shifts.', example_ko_4 = '쿤은 과학이 패러다임 전환을 통해 발전한다고 주장했어요.', example_en_5 = 'We need a new paradigm for understanding digital literacy.', example_ko_5 = '디지털 리터러시를 이해하기 위한 새로운 패러다임이 필요해요.' WHERE id = 'w_education_C1_03';
UPDATE words SET example_en_2 = 'The Socratic dialectic proceeds through question and refutation.', example_ko_2 = '소크라테스의 변증법은 질문과 반박을 통해 진행돼요.', example_en_3 = 'Dialectic reasoning helps resolve apparent contradictions in theory.', example_ko_3 = '변증법적 추론은 이론의 명백한 모순을 해결하는 데 도움이 돼요.', example_en_4 = 'The seminar used dialectic discussion to explore competing views.', example_ko_4 = '세미나에서는 변증법적 토론을 통해 경쟁하는 관점들을 탐구했어요.', example_en_5 = 'Marx adapted Hegel''s dialectic for a materialist framework.', example_ko_5 = '마르크스는 헤겔의 변증법을 유물론적 틀에 맞게 변용했어요.' WHERE id = 'w_education_C1_04';
UPDATE words SET example_en_2 = 'Hermeneutics is central to the interpretation of historical texts.', example_ko_2 = '해석학은 역사적 텍스트 해석의 핵심이에요.', example_en_3 = 'She applied hermeneutics to analyse educational policy documents.', example_ko_3 = '그녀는 교육 정책 문서를 분석하는 데 해석학을 적용했어요.', example_en_4 = 'Gadamer''s hermeneutics emphasises the fusion of horizons.', example_ko_4 = '가다머의 해석학은 지평의 융합을 강조해요.', example_en_5 = 'Hermeneutics enables us to contextualise meaning within culture.', example_ko_5 = '해석학을 통해 우리는 문화적 맥락 안에서 의미를 파악할 수 있어요.' WHERE id = 'w_education_C1_05';
UPDATE words SET example_en_2 = 'Constructivism holds that learners build knowledge through experience.', example_ko_2 = '구성주의는 학습자가 경험을 통해 지식을 쌓는다고 주장해요.', example_en_3 = 'Her classroom was designed around constructivism principles.', example_ko_3 = '그녀의 교실은 구성주의 원리를 중심으로 설계됐어요.', example_en_4 = 'Piaget''s constructivism influenced decades of curriculum design.', example_ko_4 = '피아제의 구성주의는 수십 년간 교육과정 설계에 영향을 미쳤어요.', example_en_5 = 'Social constructivism places emphasis on collaborative knowledge-building.', example_ko_5 = '사회적 구성주의는 협력적 지식 구축을 강조해요.' WHERE id = 'w_education_C1_06';
UPDATE words SET example_en_2 = 'Positivism insists that only empirically verifiable claims are meaningful.', example_ko_2 = '실증주의는 경험적으로 검증 가능한 주장만이 의미 있다고 주장해요.', example_en_3 = 'Her critique challenged the positivism underpinning mainstream psychology.', example_ko_3 = '그녀의 비판은 주류 심리학의 기반이 되는 실증주의에 의문을 제기했어요.', example_en_4 = 'Positivism dominated social science research throughout much of the twentieth century.', example_ko_4 = '실증주의는 20세기 대부분 동안 사회과학 연구를 지배했어요.', example_en_5 = 'Critics argue that positivism fails to account for subjective meaning.', example_ko_5 = '비평가들은 실증주의가 주관적 의미를 설명하지 못한다고 주장해요.' WHERE id = 'w_education_C1_07';
UPDATE words SET example_en_2 = 'Ontology examines the fundamental nature of being and existence.', example_ko_2 = '존재론은 존재와 실재의 근본적 본질을 탐구해요.', example_en_3 = 'A researcher''s ontology shapes the questions they ask.', example_ko_3 = '연구자의 존재론은 그가 제기하는 질문의 형태를 결정해요.', example_en_4 = 'Her ontology positioned reality as socially constructed.', example_ko_4 = '그녀의 존재론은 현실을 사회적으로 구성된 것으로 봤어요.', example_en_5 = 'Ontology and epistemology are deeply intertwined in qualitative research.', example_ko_5 = '존재론과 인식론은 질적 연구에서 깊이 연결돼 있어요.' WHERE id = 'w_education_C1_08';
UPDATE words SET example_en_2 = 'Each axiom in the system must be logically consistent.', example_ko_2 = '시스템의 각 공리는 논리적으로 일관성이 있어야 해요.', example_en_3 = 'The argument rests on an unexamined axiom about human nature.', example_ko_3 = '그 주장은 인간 본성에 대한 검토되지 않은 공리에 근거하고 있어요.', example_en_4 = 'Euclid''s axioms formed the basis of geometry for two millennia.', example_ko_4 = '유클리드의 공리는 2000년 동안 기하학의 기초를 이루었어요.', example_en_5 = 'We should not accept this as an axiom without critical scrutiny.', example_ko_5 = '우리는 이것을 비판적 검토 없이 공리로 받아들여서는 안 돼요.' WHERE id = 'w_education_C1_09';
UPDATE words SET example_en_2 = 'Deductive reasoning moves from general principles to specific conclusions.', example_ko_2 = '연역적 추론은 일반 원칙에서 특정 결론으로 나아가요.', example_en_3 = 'The study used a deductive approach to test existing theory.', example_ko_3 = '그 연구는 기존 이론을 검증하기 위해 연역적 접근법을 사용했어요.', example_en_4 = 'A deductive argument is valid if the conclusion follows necessarily.', example_ko_4 = '연역적 논증은 결론이 필연적으로 도출될 때 타당해요.', example_en_5 = 'She favoured deductive methodology to derive testable hypotheses.', example_ko_5 = '그녀는 검증 가능한 가설을 도출하기 위해 연역적 방법론을 선호했어요.' WHERE id = 'w_education_C1_10';
UPDATE words SET example_en_2 = 'Inductive reasoning draws generalisations from observed data.', example_ko_2 = '귀납적 추론은 관찰된 데이터로부터 일반화를 이끌어내요.', example_en_3 = 'Grounded theory relies on inductive analysis of qualitative material.', example_ko_3 = '근거 이론은 질적 자료의 귀납적 분석에 의존해요.', example_en_4 = 'His inductive approach yielded unexpected theoretical insights.', example_ko_4 = '그의 귀납적 접근법은 예상치 못한 이론적 통찰을 가져왔어요.', example_en_5 = 'An inductive method allows theory to emerge from the data.', example_ko_5 = '귀납적 방법은 이론이 데이터로부터 자연스럽게 나타나도록 해요.' WHERE id = 'w_education_C1_11';
UPDATE words SET example_en_2 = 'Critical thinking requires evaluating evidence rather than accepting claims uncritically.', example_ko_2 = '비판적 사고는 주장을 무비판적으로 수용하는 대신 증거를 평가하는 것이에요.', example_en_3 = 'The curriculum was redesigned to foster critical thinking from an early age.', example_ko_3 = '교육과정은 어릴 때부터 비판적 사고를 함양하도록 재설계됐어요.', example_en_4 = 'Critical thinking skills are increasingly valued in the workplace.', example_ko_4 = '비판적 사고 능력은 직장에서 점점 더 중시되고 있어요.', example_en_5 = 'She demonstrated strong critical thinking in her analysis of the case study.', example_ko_5 = '그녀는 사례 연구 분석에서 뛰어난 비판적 사고를 보여줬어요.' WHERE id = 'w_education_C1_12';
UPDATE words SET example_en_2 = 'A useful heuristic can guide decision-making under uncertainty.', example_ko_2 = '유용한 발견법은 불확실한 상황에서 의사결정을 안내해줄 수 있어요.', example_en_3 = 'Teachers often rely on heuristic strategies when formal rules are unclear.', example_ko_3 = '교사들은 공식 규칙이 불분명할 때 발견적 전략에 의존하는 경우가 많아요.', example_en_4 = 'The heuristic proved effective for solving ill-defined problems.', example_ko_4 = '그 발견법은 명확하지 않은 문제를 해결하는 데 효과적이었어요.', example_en_5 = 'He developed a simple heuristic for evaluating source credibility.', example_ko_5 = '그는 출처의 신뢰성을 평가하는 간단한 발견법을 개발했어요.' WHERE id = 'w_education_C1_13';
UPDATE words SET example_en_2 = 'Metacognition involves awareness and regulation of one''s own thinking.', example_ko_2 = '메타인지는 자신의 사고에 대한 인식과 조절을 포함해요.', example_en_3 = 'Strong metacognition enables learners to identify gaps in understanding.', example_ko_3 = '강한 메타인지는 학습자가 이해의 빈틈을 파악할 수 있게 해줘요.', example_en_4 = 'The course trained students to apply metacognition to exam preparation.', example_ko_4 = '그 과정은 학생들이 시험 준비에 메타인지를 적용하도록 훈련했어요.', example_en_5 = 'Metacognition is a key predictor of academic achievement across disciplines.', example_ko_5 = '메타인지는 여러 학문 분야에서 학업 성취의 핵심 예측 요인이에요.' WHERE id = 'w_education_C1_14';
UPDATE words SET example_en_2 = 'Scaffolding provides temporary support that is gradually withdrawn as learners gain confidence.', example_ko_2 = '비계 설정은 학습자가 자신감을 얻으면서 점차 제거되는 임시 지원을 제공해요.', example_en_3 = 'The teacher used scaffolding to bridge the gap between current and target competence.', example_ko_3 = '교사는 현재 역량과 목표 역량 사이의 간격을 좁히기 위해 비계 설정을 활용했어요.', example_en_4 = 'Vygotsky''s concept of scaffolding is central to sociocultural learning theory.', example_ko_4 = '비고츠키의 비계 설정 개념은 사회문화적 학습 이론의 핵심이에요.', example_en_5 = 'Effective scaffolding is responsive to the learner''s zone of proximal development.', example_ko_5 = '효과적인 비계 설정은 학습자의 근접 발달 영역에 반응해요.' WHERE id = 'w_education_C1_15';
UPDATE words SET example_en_2 = 'Learner autonomy is cultivated through reflective practice and self-assessment.', example_ko_2 = '학습자 자율성은 성찰적 실천과 자기 평가를 통해 길러져요.', example_en_3 = 'The programme was designed to promote autonomy in postgraduate researchers.', example_ko_3 = '그 프로그램은 대학원 연구자들의 자율성을 증진하도록 설계됐어요.', example_en_4 = 'Institutional constraints can undermine learner autonomy if left unaddressed.', example_ko_4 = '제도적 제약이 해결되지 않으면 학습자 자율성을 훼손할 수 있어요.', example_en_5 = 'She argued that autonomy, not compliance, should be the goal of education.', example_ko_5 = '그녀는 교육의 목표는 순응이 아니라 자율성이어야 한다고 주장했어요.' WHERE id = 'w_education_C1_16';
UPDATE words SET example_en_2 = 'Acculturation can be a gradual and sometimes uncomfortable process.', example_ko_2 = '문화 적응은 점진적이고 때로는 불편한 과정이 될 수 있어요.', example_en_3 = 'The study examined acculturation among first-generation university students.', example_ko_3 = '그 연구는 1세대 대학생들의 문화 적응을 조사했어요.', example_en_4 = 'Acculturation does not require the abandonment of one''s original culture.', example_ko_4 = '문화 적응이 본래 문화의 포기를 요구하는 것은 아니에요.', example_en_5 = 'Language acquisition is closely linked to the process of acculturation.', example_ko_5 = '언어 습득은 문화 적응 과정과 밀접하게 연결돼 있어요.' WHERE id = 'w_education_C1_17';
UPDATE words SET example_en_2 = 'Triangulation strengthens research credibility by using multiple methods.', example_ko_2 = '삼각 검증은 여러 방법을 사용하여 연구 신뢰성을 강화해요.', example_en_3 = 'She employed triangulation of interviews, observation, and documents.', example_ko_3 = '그녀는 인터뷰, 관찰, 문서의 삼각 검증을 활용했어요.', example_en_4 = 'Triangulation helps researchers identify inconsistencies across data sources.', example_ko_4 = '삼각 검증은 연구자가 데이터 출처 간의 불일치를 파악하는 데 도움이 돼요.', example_en_5 = 'Methodological triangulation was central to the study''s validity argument.', example_ko_5 = '방법론적 삼각 검증은 연구의 타당성 논거의 핵심이었어요.' WHERE id = 'w_education_C1_18';
UPDATE words SET example_en_2 = 'Reflexivity requires researchers to interrogate their own assumptions.', example_ko_2 = '반성성은 연구자가 자신의 전제를 검토하도록 요구해요.', example_en_3 = 'She maintained a reflexivity journal throughout the fieldwork period.', example_ko_3 = '그녀는 현장 조사 기간 내내 반성성 일지를 작성했어요.', example_en_4 = 'Reflexivity distinguishes rigorous qualitative research from anecdote.', example_ko_4 = '반성성은 엄밀한 질적 연구와 단순한 일화를 구분 짓는 요소예요.', example_en_5 = 'Without reflexivity, researchers risk imposing their worldview on participants.', example_ko_5 = '반성성이 없으면 연구자는 자신의 세계관을 참여자에게 투영할 위험이 있어요.' WHERE id = 'w_education_C1_19';
UPDATE words SET example_en_2 = 'An epistemological stance shapes every decision in the research process.', example_ko_2 = '인식론적 입장은 연구 과정의 모든 결정을 형성해요.', example_en_3 = 'The paper reveals the epistemological tensions between the two frameworks.', example_ko_3 = '그 논문은 두 틀 사이의 인식론적 긴장을 드러내요.', example_en_4 = 'She took an epistemological position aligned with interpretivism.', example_ko_4 = '그녀는 해석주의에 부합하는 인식론적 입장을 취했어요.', example_en_5 = 'Epistemological pluralism allows researchers to draw on multiple traditions.', example_ko_5 = '인식론적 다원주의는 연구자가 여러 전통을 활용할 수 있도록 해요.' WHERE id = 'w_education_C1_20';
UPDATE words SET example_en_2 = 'Normative claims prescribe how things ought to be, not how they are.', example_ko_2 = '규범적 주장은 사물이 어떠한지가 아니라 어떠해야 하는지를 규정해요.', example_en_3 = 'The report conflates descriptive findings with normative recommendations.', example_ko_3 = '그 보고서는 기술적 발견과 규범적 권고를 혼동하고 있어요.', example_en_4 = 'Her normative theory of justice drew on both liberal and communitarian thought.', example_ko_4 = '그녀의 정의에 관한 규범적 이론은 자유주의와 공동체주의 사상을 모두 참조했어요.', example_en_5 = 'Researchers must be transparent about normative assumptions in their work.', example_ko_5 = '연구자들은 자신의 연구에서 규범적 전제를 투명하게 밝혀야 해요.' WHERE id = 'w_education_C1_21';
UPDATE words SET example_en_2 = 'Freire''s concept of praxis links theoretical reflection with transformative action.', example_ko_2 = '프레이리의 프락시스 개념은 이론적 성찰을 변혁적 실천과 연결해요.', example_en_3 = 'The programme sought to embed praxis at every stage of teacher training.', example_ko_3 = '그 프로그램은 교사 훈련의 모든 단계에 프락시스를 내재화하고자 했어요.', example_en_4 = 'Praxis demands that theory be tested and refined through lived experience.', example_ko_4 = '프락시스는 이론이 살아있는 경험을 통해 검증되고 정제될 것을 요구해요.', example_en_5 = 'Without praxis, critical theory risks remaining detached from social reality.', example_ko_5 = '프락시스 없이는 비판 이론이 사회적 현실과 분리될 위험이 있어요.' WHERE id = 'w_education_C1_22';
UPDATE words SET example_en_2 = 'Discourse analysis examines how language constructs social reality.', example_ko_2 = '담화 분석은 언어가 어떻게 사회적 현실을 구성하는지를 살펴봐요.', example_en_3 = 'She used discourse analysis to study power relations in classroom interaction.', example_ko_3 = '그녀는 담화 분석을 사용하여 교실 상호작용에서의 권력 관계를 연구했어요.', example_en_4 = 'Critical discourse analysis foregrounds the ideological dimensions of language use.', example_ko_4 = '비판적 담화 분석은 언어 사용의 이데올로기적 차원을 부각시켜요.', example_en_5 = 'Discourse analysis helped reveal the assumptions embedded in policy documents.', example_ko_5 = '담화 분석은 정책 문서에 내재된 전제를 밝히는 데 도움이 됐어요.' WHERE id = 'w_education_C1_23';
UPDATE words SET example_en_2 = 'The limited sample size compromises the generalisability of the findings.', example_ko_2 = '제한된 표본 크기는 연구 결과의 일반화 가능성을 저해해요.', example_en_3 = 'Generalisability depends on the representativeness of the sample.', example_ko_3 = '일반화 가능성은 표본의 대표성에 달려 있어요.', example_en_4 = 'The authors acknowledge that cross-cultural generalisability cannot be assumed.', example_ko_4 = '저자들은 문화 간 일반화 가능성을 당연히 가정할 수 없다고 인정해요.', example_en_5 = 'Generalisability remains a central criterion for evaluating quantitative research.', example_ko_5 = '일반화 가능성은 양적 연구를 평가하는 핵심 기준으로 남아 있어요.' WHERE id = 'w_education_C1_24';
UPDATE words SET example_en_2 = 'Construct validity ensures that the measure captures the intended concept.', example_ko_2 = '구성 타당성은 측정 도구가 의도한 개념을 포착하는지 확인해요.', example_en_3 = 'The panel questioned the validity of the assessment instrument.', example_ko_3 = '패널은 평가 도구의 타당성에 의문을 제기했어요.', example_en_4 = 'Establishing validity is an ongoing process, not a one-time check.', example_ko_4 = '타당성 확립은 일회성 확인이 아닌 지속적인 과정이에요.', example_en_5 = 'Her study used member-checking to strengthen the validity of the analysis.', example_ko_5 = '그녀의 연구는 분석의 타당성을 강화하기 위해 구성원 확인 절차를 사용했어요.' WHERE id = 'w_education_C1_25';
UPDATE words SET example_en_2 = 'Reliability refers to the consistency of a measure across time and contexts.', example_ko_2 = '신뢰성은 시간과 맥락에 걸친 측정의 일관성을 의미해요.', example_en_3 = 'The high inter-rater reliability indicates robust coding procedures.', example_ko_3 = '높은 평가자 간 신뢰성은 탄탄한 코딩 절차를 나타내요.', example_en_4 = 'Without reliability, the findings cannot be trusted or reproduced.', example_ko_4 = '신뢰성이 없으면 연구 결과를 신뢰하거나 재현할 수 없어요.', example_en_5 = 'Reliability and validity must both be established for rigorous research.', example_ko_5 = '엄밀한 연구를 위해서는 신뢰성과 타당성을 모두 확립해야 해요.' WHERE id = 'w_education_C1_26';
UPDATE words SET example_en_2 = 'Replication of the study in a different context confirmed the original findings.', example_ko_2 = '다른 맥락에서의 연구 재현이 원래의 연구 결과를 확인해줬어요.', example_en_3 = 'The crisis in psychology was partly triggered by failures of replication.', example_ko_3 = '심리학의 위기는 부분적으로 재현 실패로 인해 촉발됐어요.', example_en_4 = 'Replication is a cornerstone of the scientific method.', example_ko_4 = '재현은 과학적 방법의 초석이에요.', example_en_5 = 'The methodology section must be detailed enough to allow replication.', example_ko_5 = '방법론 부분은 재현이 가능할 만큼 충분히 상세해야 해요.' WHERE id = 'w_education_C1_27';
UPDATE words SET example_en_2 = 'Only peer-reviewed sources were included in the literature review.', example_ko_2 = '문헌 검토에는 동료 심사를 거친 자료만 포함됐어요.', example_en_3 = 'Publishing in a peer-reviewed journal enhances the credibility of research.', example_ko_3 = '동료 심사 저널에 게재하는 것은 연구의 신뢰성을 높여줘요.', example_en_4 = 'The peer-reviewed process can take several months from submission to acceptance.', example_ko_4 = '동료 심사 과정은 제출부터 승인까지 몇 달이 걸릴 수 있어요.', example_en_5 = 'She was advised to cite only peer-reviewed articles in her dissertation.', example_ko_5 = '그녀는 논문에서 동료 심사 논문만 인용하도록 권고를 받았어요.' WHERE id = 'w_education_C1_28';
UPDATE words SET example_en_2 = 'The conceptual framework draws on Vygotskian and Freirean traditions.', example_ko_2 = '개념적 틀은 비고츠키와 프레이리의 전통에서 비롯돼요.', example_en_3 = 'A robust conceptual framework guides data collection and interpretation.', example_ko_3 = '탄탄한 개념적 틀은 데이터 수집과 해석을 안내해줘요.', example_en_4 = 'She mapped the conceptual framework visually to aid reader comprehension.', example_ko_4 = '그녀는 독자의 이해를 돕기 위해 개념적 틀을 시각적으로 도식화했어요.', example_en_5 = 'Without a clear conceptual framework, the research question lacks focus.', example_ko_5 = '명확한 개념적 틀이 없으면 연구 질문의 초점이 흐려져요.' WHERE id = 'w_education_C1_29';
UPDATE words SET example_en_2 = 'A thorough literature review identifies gaps that the study will address.', example_ko_2 = '철저한 문헌 검토는 연구가 다룰 공백을 파악해줘요.', example_en_3 = 'The literature review synthesised sixty studies published over two decades.', example_ko_3 = '문헌 검토는 20년에 걸쳐 발표된 60편의 연구를 종합했어요.', example_en_4 = 'A systematic literature review reduces the risk of selection bias.', example_ko_4 = '체계적인 문헌 검토는 선택 편향의 위험을 줄여줘요.', example_en_5 = 'The supervisor asked her to expand the literature review to include recent publications.', example_ko_5 = '지도 교수는 최근 발표 문헌을 포함하도록 문헌 검토를 확장할 것을 요청했어요.' WHERE id = 'w_education_C1_30';
UPDATE words SET example_en_2 = 'Purposive sampling selects participants based on specific criteria.', example_ko_2 = '목적적 표집은 특정 기준에 따라 참여자를 선택해요.', example_en_3 = 'Random sampling reduces systematic bias in quantitative research.', example_ko_3 = '무작위 표집은 양적 연구에서 체계적 편향을 줄여줘요.', example_en_4 = 'The sampling strategy must be aligned with the research design.', example_ko_4 = '표집 전략은 연구 설계와 일치해야 해요.', example_en_5 = 'Stratified sampling ensures representation across key subgroups.', example_ko_5 = '층화 표집은 핵심 하위 집단 전반에 걸친 대표성을 보장해요.' WHERE id = 'w_education_C1_31';
UPDATE words SET example_en_2 = 'Researchers must operationalise abstract constructs clearly before data collection.', example_ko_2 = '연구자들은 데이터 수집 전에 추상적 구성 개념을 명확하게 조작화해야 해요.', example_en_3 = 'It is challenging to operationalise concepts like wellbeing or engagement.', example_ko_3 = '행복감이나 참여도 같은 개념을 조작화하는 것은 쉽지 않아요.', example_en_4 = 'The team met to agree on how to operationalise each key variable.', example_ko_4 = '팀은 각 핵심 변수를 어떻게 조작화할지 합의하기 위해 모였어요.', example_en_5 = 'How you operationalise a concept affects every subsequent stage of analysis.', example_ko_5 = '개념을 어떻게 조작화하느냐는 이후 분석의 모든 단계에 영향을 미쳐요.' WHERE id = 'w_education_C1_32';
UPDATE words SET example_en_2 = 'The authors posit that motivation is the primary driver of language acquisition.', example_ko_2 = '저자들은 동기 부여가 언어 습득의 주요 원동력이라고 주장해요.', example_en_3 = 'It would be premature to posit a causal relationship without further evidence.', example_ko_3 = '추가 증거 없이 인과 관계를 주장하는 것은 섣부른 일이에요.', example_en_4 = 'She posits that identity and language learning are inseparable.', example_ko_4 = '그녀는 정체성과 언어 학습은 분리할 수 없다고 주장해요.', example_en_5 = 'The framework posits three stages in the development of academic literacy.', example_ko_5 = '그 틀은 학문적 리터러시 발달에 세 단계가 있다고 주장해요.' WHERE id = 'w_education_C1_33';
UPDATE words SET example_en_2 = 'The second experiment was designed to substantiate the initial findings.', example_ko_2 = '두 번째 실험은 초기 발견을 입증하기 위해 설계됐어요.', example_en_3 = 'You need stronger evidence to substantiate such a broad claim.', example_ko_3 = '그러한 광범위한 주장을 입증하려면 더 강력한 증거가 필요해요.', example_en_4 = 'The longitudinal data helped substantiate the theoretical model.', example_ko_4 = '종단적 데이터는 이론적 모델을 입증하는 데 도움이 됐어요.', example_en_5 = 'Her fieldwork provided the empirical grounding needed to substantiate the argument.', example_ko_5 = '그녀의 현장 조사는 주장을 입증하는 데 필요한 경험적 근거를 제공했어요.' WHERE id = 'w_education_C1_34';
UPDATE words SET example_en_2 = 'A nuanced reading of the data reveals internal contradictions.', example_ko_2 = '데이터에 대한 세밀한 읽기는 내부 모순을 드러내요.', example_en_3 = 'The report offers a nuanced account of the policy''s mixed outcomes.', example_ko_3 = '그 보고서는 정책의 복합적 결과에 대해 세밀한 설명을 제공해요.', example_en_4 = 'Her analysis was praised for its nuanced treatment of cultural difference.', example_ko_4 = '그녀의 분석은 문화적 차이를 세밀하게 다룬 것으로 높이 평가받았어요.', example_en_5 = 'A nuanced perspective resists oversimplification and binary thinking.', example_ko_5 = '세밀한 관점은 지나친 단순화와 이분법적 사고를 거부해요.' WHERE id = 'w_education_C1_35';

